# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int playerHealth = 100;
    public int playerCurrency = 500;
    public int damage = 10;

    public void TakeDamage(int amount)
    {
        playerHealth -= amount;
        if (playerHealth < 0)
        {
            playerHealth = 0;
        }
    }

    public bool PurchaseItem(int itemPrice)
    {
        if (playerCurrency >= itemPrice)
        {
            playerCurrency -= itemPrice;
            return true;
        }
        return false;
    }

    public void IncreaseDamage(int damageBoost)
    {
        damage += damageBoost;
    }
}

public class Shop : MonoBehaviour
{
    public int healthPotionPrice = 50;
    public int damageBoostPrice = 100;

    private PlayerStats playerStats;

    void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
    }

    public void BuyHealthPotion()
    {
        if (playerStats.PurchaseItem(healthPotionPrice))
        {
            playerStats.playerHealth += 50;
        }
    }

    public void BuyDamageBoost()
    {
        if (playerStats.PurchaseItem(damageBoostPrice))
        {
            playerStats.IncreaseDamage(10);
        }
    }
}